}
@keyframes check-in {
  0%   { transform: scale(0); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

/* Particle burst */
@keyframes burst-particle {
  0%   { transform: translate(0, 0) scale(1); opacity: 1; }
  100% { transform: translate(var(--bx), var(--by)) scale(0); opacity: 0; }
}

/* === Reduced Motion === */

@media (prefers-reduced-motion: reduce) {
  .r-all,
  .r-rt, .r-rs,
  .r-lt, .r-ls,
  .r-rua, .r-rfa,
  .r-lua, .r-lfa {
    animation: none;
  }

  .check-appear {
    animation: none;
    opacity: 1;
    transform: scale(1);
  }
}
```

**Key details:**
- All keyframes use the exact same timing (0.36s cycle) and transform-origin values as the mockup
- The CSS uses `var(--c)` for agent color (set inline on the SVG element)
- Reduced motion media query disables all running animations, showing a static figure
- The `check-appear` animation has a 0.15s delay (built into the animation shorthand) so it starts after the burst particles begin to clear
- `burst-particle` uses CSS custom properties `--bx` and `--by` set inline on each span

**Acceptance criteria:**
- All 12 animation classes match the mockup exactly
- Reduced motion media query disables all running/burst animations
- File is importable from `AgentRunner.tsx` via `import './agent-runner.css'`

Create the particle burst component that plays when an agent completes.

**File:** `apps/client/src/layers/features/chat/ui/AgentRunnerBurst.tsx`

**Props:**

```typescript
interface AgentRunnerBurstProps {
  color: string;
}
```

**Implementation:**

```tsx
import './agent-runner.css';

/** Particle burst celebration — 8 colored particles explode outward from center. */
export function AgentRunnerBurst({ color }: AgentRunnerBurstProps) {
  // 8 particles with pre-defined directions and staggered delays
  const particles = [
    { bx: '-8px', by: '-10px', delay: '0s' },
    { bx: '8px', by: '-8px', delay: '0.03s' },
    { bx: '-6px', by: '6px', delay: '0.06s' },
    { bx: '10px', by: '4px', delay: '0.09s' },
    { bx: '0px', by: '-12px', delay: '0.04s' },
    { bx: '-10px', by: '0px', delay: '0.07s' },
    { bx: '6px', by: '10px', delay: '0.05s' },
    { bx: '-4px', by: '-6px', delay: '0.08s' },
  ] as const;

  return (
    <div className="pointer-events-none absolute inset-0">
      {particles.map((p, i) => (
        <span
          key={i}
          className="absolute top-1/2 left-1/2 size-[3px] rounded-full"
          style={{
            backgroundColor: color,
            '--bx': p.bx,
            '--by': p.by,
            animation: `burst-particle 0.5s ease-out ${p.delay} forwards`,
          } as React.CSSProperties}
        />
      ))}
    </div>
  );
}
```

**Key details:**
- Each particle is a 3x3px circle positioned at center (top/left 50%)
- Uses the `burst-particle` keyframe from `agent-runner.css` which translates by `var(--bx)`/`var(--by)` and scales to 0
- Particle directions are pre-defined to radiate outward in 8 directions
- Staggered delays from 0s to 0.09s create a natural explosion feel
- `pointer-events-none` so the burst doesn't block hover
- Total burst duration: ~0.5s (longest particle: 0.09s delay + 0.5s animation = 0.59s)

**Acceptance criteria:**
- 8 particles render and animate outward from center
- Particles use the agent's color
- Animation completes in ~0.5s
- No DOM cleanup needed — parent unmounts the component

Add the full completion lifecycle to `AgentRunner`: detect status transition, show particle burst, swap to checkmark, then allow AnimatePresence exit.

**File:** `apps/client/src/layers/features/chat/ui/AgentRunner.tsx`

**Lifecycle states (internal to the component):**

```typescript
type RunnerPhase = 'running' | 'celebrating' | 'done';
```

**Implementation:**

Add state tracking inside the component:

```typescript
import { useState, useRef, useEffect, useMemo } from 'react';
import { AgentRunnerBurst } from './AgentRunnerBurst';
import './agent-runner.css';

export function AgentRunner({ agent, index }: AgentRunnerProps) {
  const [phase, setPhase] = useState<RunnerPhase>('running');
  const prevStatusRef = useRef(agent.status);

  // Detect status transition from running → complete/error
  useEffect(() => {
    if (
      prevStatusRef.current === 'running' &&
      (agent.status === 'complete' || agent.status === 'error') &&
      phase === 'running'
    ) {
      setPhase('celebrating');

      // After 350ms: burst finishes, show checkmark
      const checkTimer = setTimeout(() => setPhase('done'), 350);
      return () => clearTimeout(checkTimer);
    }
    prevStatusRef.current = agent.status;
  }, [agent.status, phase]);

  const staggerStyle = useMemo(
    () => ({ animationDelay: `${index * 0.09}s` }),
    [index]
  );

  // Checkmark SVG for completion
  const checkmarkSvg = (
    <svg className="check-appear h-6 w-[22px]" viewBox="0 0 22 24">
      <circle cx="11" cy="12" r="7" fill="none" stroke={agent.color} strokeWidth="1.5" opacity="0.3" />
      <polyline
        points="7,12 10,15 15,9"
        fill="none"
        stroke={agent.color}
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );

  // Error icon SVG (X mark instead of checkmark)
  const errorSvg = (
    <svg className="check-appear h-6 w-[22px]" viewBox="0 0 22 24">
      <circle cx="11" cy="12" r="7" fill="none" stroke={agent.color} strokeWidth="1.5" opacity="0.3" />
      <line x1="8" y1="9" x2="14" y2="15" stroke={agent.color} strokeWidth="2" strokeLinecap="round" />
      <line x1="14" y1="9" x2="8" y2="15" stroke={agent.color} strokeWidth="2" strokeLinecap="round" />
    </svg>
  );

  return (
    <div className="group relative inline-flex" aria-label={agent.description}>
      {phase === 'running' && (
        <>{/* Running SVG figure (existing code from task 2.2) */}</>  
      )}

      {phase === 'celebrating' && (
        <div className="relative">
          {/* Keep runner visible briefly during burst */}
          {/* Running SVG (same as above) */}
          <AgentRunnerBurst color={agent.color} />
        </div>
      )}

      {phase === 'done' && (
        agent.status === 'error' ? errorSvg : checkmarkSvg
      )}

      {/* Tooltip (hide during celebration/done) */}
      {phase === 'running' && (
        <div className="...tooltip classes...">
          {/* tooltip content */}
        </div>
      )}
    </div>
  );
}
```

**Timing sequence (matching the mockup):**
1. Status changes to complete/error → phase becomes `'celebrating'`
2. Burst particles animate (0.5s duration, but we advance after 350ms)
3. After 350ms: phase becomes `'done'`, checkmark SVG renders with `check-appear` CSS animation (0.3s scale-in with 0.15s delay)
4. The parent `useRunningSubagents` hook keeps the agent in the array for 1.5s total, then removes it
5. When removed from array, `AnimatePresence` in `RunningAgentIndicator` handles the slot-collapse exit animation

**Acceptance criteria:**
- Completion transitions from running SVG → burst + runner → checkmark
- Error uses X icon instead of checkmark
- Tooltip hidden during celebration phases
- Timing matches: 350ms burst → checkmark scale-in → slot collapse after hook's 1.5s timer

